function l(o){const e=o.toLowerCase();return e.includes("close")||e.includes("\u7279\u5199")||e.includes("\u8FD1\u666F")?"close":e.includes("medium")||e.includes("\u4E2D\u666F")?"medium":e.includes("wide")||e.includes("long")||e.includes("\u5168\u666F")||e.includes("\u8FDC\u666F")?"wide":"other"}function h(o){const e=o.cameraMovement?.toLowerCase()??"";if(e.includes("slow")||e.includes("\u6162"))return"slow";if(e.includes("handheld")||e.includes("\u624B\u6301")||e.includes("fast")||e.includes("\u5FEB"))return"fast";const t=o.duration??6;return t<=5?"fast":t>=10?"slow":"medium"}function f(o){const e=[...o],t=new Set(["auto","default","","close-up","medium shot","wide shot","long shot"]);for(let s=2;s<e.length;s++){const i=l(e[s-2].shotType),c=l(e[s-1].shotType),n=l(e[s].shotType);if(i===c&&c===n&&n!=="other"){const a=e[s].shotType.toLowerCase().trim();if(t.has(a)){const u=(n==="close"?"wide":"close")==="close"?"close-up":"wide shot";e[s]={...e[s],shotType:u}}}}return e}function d(o,e,t){const s=o.sceneId===e.sceneId,i=o.emotionLabel??"",c=e.emotionLabel??"",n=i&&c&&i!==c;if(s){const a=l(o.shotType),r=l(e.shotType);return a!==r?{shotIndex:t,type:"match-cut",reason:`Same scene ${e.sceneId}, scale change ${o.shotType}\u2192${e.shotType} suggests match-cut for spatial continuity`}:{shotIndex:t,type:"cut",reason:`Same scene ${e.sceneId}, standard cut within scene`}}return n?{shotIndex:t,type:"smash",reason:`Scene change ${o.sceneId}\u2192${e.sceneId} with emotion shift ${i}\u2192${c}, smash cut for dramatic contrast`}:{shotIndex:t,type:"dissolve",reason:`Scene change ${o.sceneId}\u2192${e.sceneId}, dissolve for smooth passage`}}function m(o){const e=o.map(h),t=[];let s=0;for(let n=1;n<=e.length;n++)if(n===e.length||e[n]!==e[s]){const a=n-s;if(a>=3){const r=e[s];r==="slow"?t.push(`Shots ${s+1}-${n}: sustained slow pacing (${a} shots) \u2014 consider inserting a fast beat for contrast`):r==="fast"&&t.push(`Shots ${s+1}-${n}: sustained fast pacing (${a} shots) \u2014 risk of viewer fatigue, consider a breathing shot`)}s=n}const i=e.filter(n=>n==="slow").length,c=e.filter(n=>n==="fast").length;return c>i*2?t.push("Overall rhythm: high-intensity sequence \u2014 fast pacing dominates, suitable for action/confrontation scenes"):i>c*2?t.push("Overall rhythm: contemplative sequence \u2014 slow pacing dominates, suitable for emotional/atmospheric scenes"):t.push("Overall rhythm: balanced \u2014 alternating fast and slow beats create natural dramatic flow"),{curve:e,notes:t}}export function directSequence(o){const e=f(o),t=[];for(let c=1;c<e.length;c++)t.push(d(e[c-1],e[c],c));const{curve:s,notes:i}=m(e);return{shots:e,transitions:t,rhythmCurve:s,notes:i}}
